import { useEffect, useRef, useState } from "react";
import { useInView } from "./helpers";

function CountUp({target, duration=1800, trigger}) {
  const [val, setVal] = useState(0);
  const raf = useRef(null);
  useEffect(()=>{
    if(!trigger) return;
    const start = performance.now();
    const run = (now)=>{
      const t = Math.min((now-start)/duration, 1);
      const e = t<0.5?2*t*t:1-Math.pow(-2*t+2,2)/2;
      setVal(+(target*e).toFixed(1));
      if(t<1) raf.current = requestAnimationFrame(run);
      else setVal(target);
    };
    raf.current = requestAnimationFrame(run);
    return ()=>cancelAnimationFrame(raf.current);
  },[trigger,target,duration]);
  return <>{val}</>;
}

const AIMS = [
  "Understanding the fraud-prone segments of the gig economy workforce",
  "Examining structural blind spots in the current risk assessment processes",
  "Quantifying these blind spots, uncovering fraud patterns, and highlighting where risk is quietly concentrating",
  "Covering real-life fraud stories that IDfy witnessed last year",
];

export default function WhyReportSection() {
  const [ref, visible] = useInView(0.2);

  return (
    <section style={{background:"#fff",padding:"100px 8vw"}}>
      <h2 style={{
        fontFamily:"'Playfair Display','Georgia',serif",
        fontSize:"clamp(28px,3.5vw,52px)",fontWeight:700,
        color:"#1a1a1a",textAlign:"center",marginBottom:72,
      }}>
        Why we put this report together
      </h2>

      <div ref={ref} style={{
        display:"flex",gap:60,alignItems:"flex-start",
        flexWrap:"wrap",maxWidth:1100,margin:"0 auto",
      }}>
        {/* Left — big stat */}
        <div style={{flex:"0 0 auto",minWidth:260}}>
          <p style={{
            fontSize:18,color:"#555",fontWeight:400,marginBottom:8,
            opacity:visible?1:0,transform:visible?"translateY(0)":"translateY(20px)",
            transition:"opacity 0.5s, transform 0.5s",
          }}>We analyzed over</p>

          <div style={{
            fontFamily:"'Playfair Display',serif",
            fontSize:"clamp(64px,9vw,110px)",
            fontWeight:900,color:"#e53e3e",lineHeight:0.95,
            opacity:visible?1:0,transform:visible?"translateY(0)":"translateY(20px)",
            transition:"opacity 0.5s 0.1s, transform 0.5s 0.1s",
          }}>
            <CountUp target={4.9} trigger={visible} duration={1600}/>M
          </div>

          <p style={{
            fontSize:"clamp(22px,2.5vw,34px)",fontWeight:800,color:"#1a1a1a",
            lineHeight:1.2,marginTop:8,marginBottom:10,
            opacity:visible?1:0,transform:visible?"translateY(0)":"translateY(20px)",
            transition:"opacity 0.5s 0.2s, transform 0.5s 0.2s",
          }}>Background<br/>Verifications</p>

          <p style={{
            fontSize:16,color:"#666",lineHeight:1.6,
            opacity:visible?1:0,transform:visible?"translateY(0)":"translateY(20px)",
            transition:"opacity 0.5s 0.3s, transform 0.5s 0.3s",
          }}>conducted last year to build<br/>this report,</p>
        </div>

        {/* Right — aims box */}
        <div style={{
          flex:1,minWidth:300,
          background:"#f5f5f5",borderRadius:16,padding:"32px 36px",
          opacity:visible?1:0,transform:visible?"translateX(30px)":"translateX(30px)",
          transition:"opacity 0.6s 0.25s, transform 0.6s 0.25s",
        }}
        /* override transform when visible */
        ref={el=>{ if(el && visible) { el.style.transform="translateX(0)"; el.style.opacity="1"; } }}
        >
          <p style={{fontSize:15,color:"#888",fontWeight:600,marginBottom:20,letterSpacing:0.3}}>
            with the aim of
          </p>
          <ul style={{listStyle:"none",padding:0,display:"flex",flexDirection:"column",gap:20}}>
            {AIMS.map((aim,i)=>(
              <li key={i} style={{
                display:"flex",gap:14,alignItems:"flex-start",
                opacity:visible?1:0,
                transform:visible?"translateY(0)":"translateY(14px)",
                transition:`opacity 0.4s ${0.35+0.1*i}s, transform 0.4s ${0.35+0.1*i}s`,
              }}>
                <span style={{
                  flexShrink:0,width:10,height:10,borderRadius:"50%",
                  background:"#e53e3e",marginTop:5,
                }}/>
                <span style={{fontSize:15,color:"#333",lineHeight:1.65}}>{aim}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </section>
  );
}
